mapper.update:
UPDATE esg.tb_training_plan_training_location
SET location_nm = #{locationNm},
remark = #{remark},
ord_seq = #{ordSeq},
use_yn = #{useYn}
WHERE comp_id = #{compId}
AND location_id = #{locationId}

mapper.delete:
UPDATE esg.tb_training_plan_implementation
SET
use_yn = 'N',
updated_at = now(),
updated_by = #{updatedBy}
WHERE comp_id = #{compId}
AND write_year = #{writeYear}
AND doc_no = #{docNo}
AND doc_type = #{docType}

mapper.select:
SELECT *, b.hr_nm, c.orgn_nm, d.jbrp_nm
FROM esg.tb_training_plan_implementation_learner  a
LEFT JOIN esg.tb_hr_info b ON a.hr_id = b.hr_id
LEFT JOIN esg.tb_orgn_info c ON b.orgn_id = c.orgn_id
LEFT JOIN esg.tb_hr_info_jbrp d ON c.comp_id = d.comp_id AND b.jbrp = d.jbrp_id
WHERE write_year = #{writeYear}
AND doc_type = #{docType}
AND doc_no = #{docNo}

