DELETE FROM esg.tb_training_plan_implementation_learner
WHERE write_year = #{writeYear}
AND doc_type = #{docType}
AND doc_no = #{docNo}

DELETE FROM esg.tb_training_plan_implementation_hr
WHERE write_year = #{writeYear}
AND doc_no = #{docNo}
AND doc_type = #{docType}

mapper.select:
SELECT *
FROM esg.tb_training_plan_implementation
WHERE comp_id = #{compId}
AND write_year = #{writeYear}
AND doc_no = #{docNo}
AND doc_type = #{docType}

select t1.doc_no
from esg.tb_training_plan_implementation t1
where t1.use_yn = 'Y'
and t1.write_year = #{writeYear}
and t1.comp_id = #{compId}
and substring(t1.training_date from 5 for 2) = #{searchText}
order by t1.training_date asc
